import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Entwicklungsumgebung einrichten","description":"Ein Schritt-für-Schritt-Leitfaden, wie man eine Entwicklungsumgebung für die Erstellung von Mods mit Fabric einrichtet.","frontmatter":{"title":"Entwicklungsumgebung einrichten","description":"Ein Schritt-für-Schritt-Leitfaden, wie man eine Entwicklungsumgebung für die Erstellung von Mods mit Fabric einrichtet.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"de_de/1.21.8/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.8/translated/de_de/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1760721669000}`);var o={name:`de_de/1.21.8/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Entwicklungsumgebung einrichten <a class="header-anchor" href="#h1" aria-label="Permalink to “Entwicklungsumgebung einrichten”">​</a></h1><p>Um mit der Entwicklung von Mods mit Fabric zu beginnen, musst du eine Entwicklungsumgebung mit IntelliJ IDEA einrichten.</p><h2 id="installing-jdk-21" tabindex="-1">JDK 17 installieren <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “JDK 17 installieren”">​</a></h2><p>Um Mods für Minecraft 1.21.4 zu entwickeln, benötigst du ein JDK 21.</p><p>Wenn du Hilfe bei der Installation von Java benötigst, kannst du die verschiedenen Java-Installationsanleitungen im Abschnitt <a href="./../../players/index">Leitfäden für Spieler</a> nachlesen.</p><h2 id="installing-intellij-idea" tabindex="-1">IntelliJ IDEA installieren <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “IntelliJ IDEA installieren”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Natürlich kannst du auch andere IDEs verwenden, wie zum Beispiel Eclipse oder Visual Studio Code, aber die meisten Seiten dieser Dokumentation gehen davon aus, dass du IntelliJ IDEA verwendest - wenn du eine andere IDE verwendest, solltest du die Dokumentation für deine IDE lesen.</p></div><p>Wenn du IntelliJ IDEA nicht installiert hast, kannst du es von der <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">offiziellen Website</a> herunterladen - befolge die Installationsschritte für dein Betriebssystem.</p><p>Die Community-Edition von IntelliJ IDEA ist kostenlos und Open Source, und sie ist die empfohlene Version für das Modding mit Fabric.</p><p>Möglicherweise musst du nach unten scrollen, um den Download-Link für die Community-Edition zu finden - er sieht wie folgt aus:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="Aufforderung für den Download der IDEA Community Edition" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">IDEA Plugins installieren <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “IDEA Plugins installieren”">​</a></h2><p>Obwohl diese Plugins nicht unbedingt notwendig sind, können sie das Modding mit Fabric erheblich erleichtern - deshalb solltest du in Erwägung ziehen, sie zu installieren.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Das Minecraft Development Plugin bietet Unterstützung für das Modding mit Fabric und ist das wichtigste Plugin, das man installieren sollte.</p><p>Du kannst es installieren, indem du IntelliJ IDEA öffnest und dann zu <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> navigierst - suche nach <code>Minecraft Development</code> in der Suchleiste und klicke dann auf die <code>Install</code> Schaltfläche.</p><p>Alternativ kannst du es von der <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">Plugin-Seite</a> herunterladen und dann installieren, indem du zu <code>File &gt; Settings &gt; Plugins &gt; Install Plugin From Disk</code> navigierst.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};